<script lang="ts">import{dndFeature,expansionFeature}from'@fex/components-core';import{createTreeController}from'@fex/components-core/tree/create-tree-controller';import{TreeRoot,TreeViewport}from'@fex/components-svelte/primitive/tree';import Card from'@fex/components-svelte/ui/card';import DndTreeRow from'./dnd-tree-row.svelte';import{departmentFieldNames,departmentTreeData,isDepartmentLeaf,type DepartmentNode}from'./data';const controller=createTreeController<DepartmentNode>({treeData:departmentTreeData,fieldNames:departmentFieldNames,isLeaf:isDepartmentLeaf,features:[expansionFeature({defaultExpandedKeys:['company','engineering','product']}),dndFeature()]})</script><Card title="Optional drag and drop feature" description="This example uses a custom 24px indent. Vertical edge zones reorder; in the middle zone, dropping in the target row's trailing half makes the source a child, while moving left can outdent it."><TreeRoot {controller} indent={24} class="max-w-xl rounded-md border border-border bg-background p-space-sm">{#snippet children()}<TreeViewport>{#snippet children(item)}<DndTreeRow {controller} itemKey={item.key}/>{/snippet}</TreeViewport>{/snippet}</TreeRoot></Card>
